#!/usr/bin/env python3
import sys

def alphabet_position(s: str):
    return [ord(ch.lower()) - ord('a') + 1 for ch in s if ch.isalpha()]

def main():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    T = int(data[0].strip())
    out_lines = []
    for i in range(1, T + 1):
        line = data[i] if i < len(data) else ''
        positions = alphabet_position(line)
        out_lines.append(str(positions))
    sys.stdout.write('
'.join(out_lines))

if __name__ == "__main__":
    main()

